<template>
  <div class="guide-root">
    <!-- 顶部导航栏 -->
    <header class="guide-header">
      <div class="guide-header__left">
        <RouterLink to="/guide" class="guide-header__logo">
          <span class="guide-header__logo-icon">📐</span>
          <span class="guide-header__logo-text">FlowDesigner 手册</span>
        </RouterLink>
        <span class="guide-header__version">v1.0</span>
      </div>
      <div class="guide-header__right">
        <a href="https://x6.antv.antgroup.com" target="_blank" class="guide-header__link" style="color: #1677ff;">X6官方文档 ↗</a>
        <RouterLink to="/" class="guide-header__link">← 返回演示</RouterLink>
      </div>
    </header>

    <div class="guide-body">
      <!-- 左侧目录导航 -->
      <aside class="guide-sidebar">
        <nav class="guide-nav">
          <div v-for="group in navGroups" :key="group.label" class="guide-nav__group">
            <div class="guide-nav__group-label">{{ group.label }}</div>
            <RouterLink
              v-for="item in group.items"
              :key="item.path"
              :to="item.path"
              class="guide-nav__item"
              :class="{ 'guide-nav__item--active': currentPath === item.path }"
            >
              <span class="guide-nav__item-num">{{ item.num }}</span>
              <span class="guide-nav__item-title">{{ item.title }}</span>
              <span v-if="isRead(item.path)" class="guide-nav__item-check">✓</span>
            </RouterLink>
          </div>
        </nav>
      </aside>

      <!-- 右侧内容区 -->
      <main class="guide-content" ref="contentRef">
        <slot />
        <!-- 上下章节导航 -->
        <div class="guide-pagination">
          <RouterLink v-if="prevChapter" :to="prevChapter.path" class="guide-pagination__btn">
            ← {{ prevChapter.title }}
          </RouterLink>
          <span v-else />
          <RouterLink v-if="nextChapter" :to="nextChapter.path" class="guide-pagination__btn">
            {{ nextChapter.title }} →
          </RouterLink>
        </div>
      </main>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, computed, watch, onMounted } from 'vue'
import { RouterLink, useRoute } from 'vue-router'

const route = useRoute()
const contentRef = ref<HTMLElement>()

const chapters = [
  { num: '01', title: '认识 FlowDesignerLayout', path: '/guide/introduction' },
  { num: '02', title: '基础使用', path: '/guide/basic-usage' },
  { num: '03', title: 'FlowDesigner 参数与方法', path: '/guide/flowdesigner-api' },
  { num: '04', title: '插槽系统', path: '/guide/slots' },
  { num: '05', title: '权限系统', path: '/guide/permissions' },
  { num: '06', title: '自定义节点', path: '/guide/elements' },
  { num: '07', title: '快捷键', path: '/guide/shortcuts' },
  { num: '08', title: '元素状态', path: '/guide/element-states' },
  { num: '09', title: '进阶技巧', path: '/guide/advanced' },
  { num: '10', title: '性能优化', path: '/guide/performance' },
]

const navGroups = [
  { label: '入门', items: chapters.slice(0, 3) },
  { label: '核心功能', items: chapters.slice(3, 8) },  // 包含索引 3-7，即插槽系统、权限系统、自定义节点、快捷键、元素状态
  { label: '进阶', items: chapters.slice(8) },  // 从索引 8 开始，即进阶技巧、性能优化
]

const currentPath = computed(() => route.path)
const currentIndex = computed(() => chapters.findIndex(c => c.path === currentPath.value))
const prevChapter = computed(() => currentIndex.value > 0 ? chapters[currentIndex.value - 1] : null)
const nextChapter = computed(() =>
  currentIndex.value >= 0 && currentIndex.value < chapters.length - 1
    ? chapters[currentIndex.value + 1]
    : null
)

const READ_KEY = 'guide_read_chapters'
const readSet = ref<Set<string>>(new Set())

function loadRead() {
  try {
    const raw = localStorage.getItem(READ_KEY)
    readSet.value = new Set(raw ? JSON.parse(raw) : [])
  } catch {
    readSet.value = new Set()
  }
}

function isRead(path: string) { return readSet.value.has(path) }

function markRead(path: string) {
  readSet.value.add(path)
  localStorage.setItem(READ_KEY, JSON.stringify([...readSet.value]))
}

onMounted(() => loadRead())

watch(currentPath, (p) => {
  if (p.startsWith('/guide/')) {
    markRead(p)
    contentRef.value?.scrollTo({ top: 0, behavior: 'smooth' })
  }
}, { immediate: true })
</script>

<style scoped>
.guide-root {
  display: flex; flex-direction: column; width: 100%; height: 100%;
  background: #f5f6fa; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  overflow: hidden;
}
.guide-header {
  display: flex; align-items: center; justify-content: space-between;
  padding: 0 24px; height: 52px; background: #fff;
  border-bottom: 1px solid #e8e8e8; box-shadow: 0 1px 4px rgba(0,0,0,0.06);
  flex-shrink: 0; z-index: 10;
}
.guide-header__left { display: flex; align-items: center; gap: 10px; }
.guide-header__logo { display: flex; align-items: center; gap: 8px; text-decoration: none; color: inherit; }
.guide-header__logo-icon { font-size: 20px; }
.guide-header__logo-text { font-size: 16px; font-weight: 600; color: #1a1a2e; }
.guide-header__version { font-size: 11px; color: #999; background: #f0f0f0; padding: 2px 7px; border-radius: 10px; }
.guide-header__right { display: flex; align-items: center; }
.guide-header__link { font-size: 13px; color: #666; text-decoration: none; transition: color 0.2s; margin-left: 20px }
.guide-header__link:hover { color: #1677ff; }
.guide-body { display: flex; flex: 1; overflow: hidden; }
.guide-sidebar {
  width: 220px; flex-shrink: 0; background: #fff;
  border-right: 1px solid #e8e8e8; overflow-y: auto; padding: 16px 0;
}
.guide-nav__group { margin-bottom: 8px; }
.guide-nav__group-label {
  font-size: 11px; font-weight: 600; color: #aaa;
  text-transform: uppercase; letter-spacing: 0.06em; padding: 4px 20px 6px;
}
.guide-nav__item {
  display: flex; align-items: center; gap: 8px; padding: 8px 20px;
  text-decoration: none; color: #555; font-size: 13px;
  border-left: 3px solid transparent; transition: background 0.15s, color 0.15s, border-color 0.15s;
}
.guide-nav__item:hover { background: #f0f5ff; color: #1677ff; }
.guide-nav__item--active { background: #e6f0ff; color: #1677ff; border-left-color: #1677ff; font-weight: 500; }
.guide-nav__item-num { font-size: 11px; color: #bbb; min-width: 22px; }
.guide-nav__item--active .guide-nav__item-num { color: #1677ff; }
.guide-nav__item-title { flex: 1; }
.guide-nav__item-check { font-size: 11px; color: #52c41a; font-weight: 700; }
.guide-content { flex: 1; overflow-y: auto; padding: 40px 48px; -max-width: 900px; }
.guide-pagination {
  display: flex; justify-content: space-between;
  margin-top: 56px; padding-top: 24px; border-top: 1px solid #e8e8e8;
}
.guide-pagination__btn {
  display: inline-flex; align-items: center; padding: 8px 18px;
  border: 1px solid #d9d9d9; border-radius: 6px; text-decoration: none;
  color: #555; font-size: 13px; background: #fff; transition: all 0.2s;
}
.guide-pagination__btn:hover { border-color: #1677ff; color: #1677ff; }
</style>
